namespace ProductReviewsDemo.Controllers
{
    public class ProductReviewsController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        public async Task<ActionResult> Details(int productId)
        {
            var product = await _db.Products
                .AsNoTracking()
                .FirstOrDefaultAsync(p => p.Id == productId);

            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = await _db.Reviews
                .AsNoTracking()
                .Where(r => r.ProductId == productId && r.IsApproved)
                .OrderByDescending(r => r.CreatedUtc)
                .Select(r => new ReviewDisplayViewModel
                {
                    Id = r.Id,
                    AuthorName = r.AuthorName,
                    Rating = r.Rating,
                    CreatedUtc = r.CreatedUtc,
                    HtmlBody = ReviewHtmlSanitizer.Sanitize(r.Body)
                })
                .ToListAsync();

            var model = new ProductReviewsPageViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = reviews
            };

            return View(model);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<ActionResult> Create(CreateReviewInputModel input)
        {
            if (!ModelState.IsValid)
            {
                return RedirectToAction("Details", new { productId = input.ProductId });
            }

            var productExists = await _db.Products.AnyAsync(p => p.Id == input.ProductId);
            if (!productExists)
            {
                return HttpNotFound();
            }

            var review = new Review
            {
                ProductId = input.ProductId,
                AuthorName = input.AuthorName?.Trim(),
                Body = input.Body?.Trim(),
                Rating = input.Rating,
                CreatedUtc = DateTime.UtcNow,
                IsApproved = true
            };

            _db.Reviews.Add(review);
            await _db.SaveChangesAsync();

            return RedirectToAction("Details", new { productId = input.ProductId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }
    }

    public static class ReviewHtmlSanitizer
    {
        public static string Sanitize(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return string.Empty;
            }

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = Regex.Replace(encoded, @"\*(.+?)\*", "<strong>$1</strong>");
            encoded = Regex.Replace(encoded, @"_(.+?)_", "<em>$1</em>");
            encoded = encoded.Replace("\r\n", "\n").Replace("\n", "<br />");

            return encoded;
        }
    }

