/* Views/ProductReviews/Details.cshtml */
@model ProductReviewsDemo.Controllers.ProductReviewsPageViewModel

@{
    ViewBag.Title = Model.ProductName + " Reviews";
}

<h2>@Model.ProductName Reviews</h2>

@if (Model.Reviews != null && Model.Reviews.Any())
{
    <div class="reviews">
        @foreach (var review in Model.Reviews)
        {
            <article class="review">
                <header>
                    <strong>@Html.Encode(review.AuthorName)</strong>
                    <span> - @review.Rating/5</span>
                    <span> - @review.CreatedUtc.ToLocalTime().ToString("g")</span>
                </header>
                <div class="review-body">
                    @Html.Raw(review.HtmlBody)
                </div>
            </article>
        }
    </div>
}
else
{
    <p>No reviews yet.</p>
}

<h3>Leave a Review</h3>

@using (Html.BeginForm("Create", "ProductReviews", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    <input type="hidden" name="ProductId" value="@Model.ProductId" />

    <div>
        <label for="AuthorName">Name</label>
        <input type="text" id="AuthorName" name="AuthorName" maxlength="100" required />
    </div>

    <div>
        <label for="Rating">Rating</label>
        <select id="Rating" name="Rating" required>
            <option value="1">1</option>
            <option value="2">2</option>
            <option value="3">3</option>
            <option value="4">4</option>
            <option value="5">5</option>
        </select>
    </div>

    <div>
        <label for="Body">Review</label>
        <textarea id="Body" name="Body" rows="6" maxlength="4000" required></textarea>
        <small>Formatting: use *bold* and _italic_</small>
    </div>

    <button type="submit">Submit Review</button>
}